12	
13	        // Arrange
14	        const options: PerseusSorterWidgetOptions = {
15	            correct: ["$15$ grams", "$55$ grams", "$0.005$ kilograms"],
16	            layout: "horizontal",
17	            padding: true,
18	        };
19	
20	        // Act
21	        const publicWidgetOptions = getSorterPublicWidgetOptions(options);
22	
23	        // Assert
24	        expect(publicWidgetOptions).toEqual({
25	            correct: ["$15$ grams", "$0.005$ kilograms", "$55$ grams"],
26	            layout: "horizontal",
27	            padding: true,
28	        });
29	    });
30	});
31	
32	describe("shuffleSorter", () => {
33	    it("does nothing given no cards", () => {
34	        expect(shuffleSorter({correct: []}, 0)).toEqual([]);
35	    });
36	
37	    describe.each(range(0, 10))("when problemNum is %d", (problemNum) => {
38	        // problemNum is used as the seed for the shuffle.
39	
40	        it("always moves the first card", () => {
41	            const shuffled = shuffleSorter(
42	                {
43	                    correct: ["1", "2", "3", "4"],
44	                },
45	                problemNum,
46	            );
47	            expect(shuffled[0]).not.toEqual(["1"]);
48	        });
49	
50	        it("preserves the set of cards", () => {
51	            const correct = ["1", "2", "3", "4"];
52	            const shuffled = shuffleSorter({correct}, problemNum);
53	            expect(new Set(shuffled)).toEqual(new Set(correct));
54	        });
55	    });
56	});
