1	import {parseAndMigratePerseusItem} from "../parse-perseus-json";
2	import {isFailure} from "../parse-perseus-json/result";
3	
4	import deepClone from "./deep-clone";
5	import splitPerseusRenderer from "./split-perseus-renderer";
6	
7	import type {PerseusItem} from "../data-schema";
8	
9	/**
10	 * Return a copy of a PerseusItem with rubric data removed (ie answers)
11	 *
12	 * @param original - the original, full PerseusItem (which includes the rubric - aka answer data)
13	 */
14	export default function splitPerseusItem(original: PerseusItem): PerseusItem {
15	    const item = deepClone(original);
16	
17	    return {
18	        ...item,
19	        question: splitPerseusRenderer(item.question),
20	        /**
21	         * We can't include the hints because they often contain the answer.
22	         *
23	         * However the UI needs to know how many hints there are before we have
24	         * answerful PerseusItems. In a crunch, we decided to replace existing hints
25	         * with empty hints and add a placeholder flag to signal that they're
26	         * not real hints.
27	         *
28	         * TODO(LEMS-3806): there's probably a better way to do this
29	         */
30	        hints: original.hints.map(() => ({
31	            content: "",
32	            widgets: {},
33	            images: {},
34	            placeholder: true,
35	        })),
36	    };
37	}
38	
39	/**
40	 * Returns a JSON copy of a PerseusItem with rubric data (i.e. answers and
41	 * hints) removed. Idempotent and deterministic.
42	 *
43	 * @param data a {@linkcode PerseusItem}, either as JSON or as an object.
44	 * @returns {string} the answerless data formatted as JSON
45	 * @throws {SyntaxError} given malformed JSON or data that can't be parsed as
46	 * a Perseus item.
47	 */
48	export function splitPerseusItemJSON(data: unknown): string {
49	    const parseResult = parseAndMigratePerseusItem(data);
50	    if (isFailure(parseResult)) {
51	        throw new SyntaxError(parseResult.detail.message);
52	    }
53	    const item = parseResult.value;
54	
55	    return JSON.stringify(splitPerseusItem(item));
56	}
